Voici comment adapter les fonctions existantes dans generic_methods.py :
pythonCopierModifierfrom app.services.Technology_Department.database_management.actions.fetch_dynamic_elements import fetch_dynamic_elements

def get_children(element_id, element_type=None, filters=None):
    # Utiliser fetch_dynamic_elements pour récupérer les enfants
    query = {
        "parent_id": element_id
    }
    if element_type:
        query["type_id"] = element_type
    if filters:
        query.update(filters)
    return fetch_dynamic_elements("elements", filters=query)

def get_parent(element_id):
    # Utiliser fetch_dynamic_elements pour récupérer le parent
    return fetch_dynamic_elements("relations", filters={"child_id": element_id}, join_tables=["elements"])

def get_siblings(element_id, filters=None):
    # Utiliser fetch_dynamic_elements pour récupérer les siblings
    parent = get_parent(element_id)
    if parent:
        parent_id = parent[0].get("parent_id")
        query = {"parent_id": parent_id, "id__not": element_id}
        if filters:
            query.update(filters)
        return fetch_dynamic_elements("elements", filters=query)
    return []

def get_tags(element_id):
    # Utiliser fetch_dynamic_elements pour récupérer les tags
    return fetch_dynamic_elements("tags", filters={"element_id": element_id}, join_tables=["elements"])

