from app.services.Technology_Department.database_management.actions.bdd_update_records import bdd_update_records
from app.services.Technology_Department.database_management.actions.bdd_delete_record import bdd_delete_record

def create_record(table, data):
    """
    Crée un nouvel enregistrement dans la base de données.
    """
    return bdd_add_records(table, [data])

def get_record(table, filters=None):
    """
    Récupère un ou plusieurs enregistrements selon des filtres.
    """
    return fetch_dynamic_elements(table=table, filters=filters)

def update_record(table, record_id, data):
    """
    Met à jour un enregistrement existant dans la base de données.
    """
