def get_children(element_id, element_type=None, filters=None):
    """
    Récupère les enfants d'un élément spécifique avec des filtres optionnels.
    """
    query = {
        "parent_id": element_id
    }
    if element_type:
        query["type_id"] = element_type
    if filters:
        query.update(filters)
    return fetch_dynamic_elements(table="elements", filters=query)

def get_parent(element_id):
    """
    Récupère le parent d'un élément.
    """
    query = {
        "child_id": element_id
    }
    return fetch_dynamic_elements(table="relations", filters=query, join_tables=["elements"])

def get_siblings(element_id, filters=None):
    """
    Récupère les éléments "siblings" d'un élément donné.
    """
    parent = get_parent(element_id)
    if parent:
        parent_id = parent[0].get("parent_id")
        query = {"parent_id": parent_id, "id__not": element_id}
        if filters:
            query.update(filters)
        return fetch_dynamic_elements(table="elements", filters=query)
    return []

def get_tags(element_id):
    """
    Récupère les tags associés à un élément spécifique.
    """
    query = {
        "element_id": element_id
    }
    return fetch_dynamic_elements(table="tags", filters=query, join_tables=["elements"])

